Given an N-ary tree, print the nodes seen by a person when walking from bottom left to bottom right in an arc via root node.

Examples:


				4
	          /    \
	        5	    7
	      /   \    /  \
	   12     1   a    8
Output: 12, 5, 4, 7, 8


We need to store  the left most and right most element of each level and BFS traversal should solve. I took lot of time to get this logic

I can't able to solve completely due to time constraints but the full solution is here:
```
import java.util.*;
import java.util.List;

class Node {
    int value;
    List<Node> children;
    Node(int value) {
        this.value = value;
        this.children = new ArrayList();
    }
}

public class Main {
  public static void main(String args[]) {
    Node root = new Node(4);
    Node child1 = new Node(5);
    Node child2 = new Node(7);

    root.children.add(child1);
    root.children.add(child2);

    child1.children.add(new Node(12));
    child1.children.add(new Node(1));
    child2.children.add(new Node(6));
    child2.children.add(new Node(8));

    List<Integer> result = leftBottomTraversal(root);
    System.out.println("Arc Traversal: " + result);
  }

    public static List<Integer> leftBottomTraversal(Node node){
        Queue<Node> queue = new LinkedList();
        List<Integer> result = new ArrayList();

        if(node == null) 
          return result;
        result.add(node.value);

        if(node.children == null) 
          return result;
        for(Node n : node.children)
            queue.add(n);

        while(!queue.isEmpty()){
            int size = queue.size();
            for(int i = 0; i < size; i++) {
                Node currNode = queue.poll();
                if(i == 0) 
                  result.add(0, currNode.value);
                else if(i == size - 1) 
                  result.add(currNode.value);
                if(currNode.children == null) 
                  continue;
                for(Node n : currNode.children)
                    queue.add(n);
            }
        }
        return result;
    }
}
